import{_ as t,o as a,c as s,ag as n}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"Design Spec: Input Bar","description":"","frontmatter":{},"headers":[],"relativePath":"design-spec/03_input_bar.md","filePath":"design-spec/03_input_bar.md","lastUpdated":1775668246000}'),i={name:"design-spec/03_input_bar.md"};function o(r,e,d,l,c,p){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="design-spec-input-bar" tabindex="-1">Design Spec: Input Bar <a class="header-anchor" href="#design-spec-input-bar" aria-label="Permalink to &quot;Design Spec: Input Bar&quot;">​</a></h1><p><strong>TS source</strong>: <code>components/PromptInput.tsx</code>, <code>hooks/useTextInput.ts</code>, <code>hooks/fileSuggestions.ts</code></p><hr><h2 id="visual-layout" tabindex="-1">Visual Layout <a class="header-anchor" href="#visual-layout" aria-label="Permalink to &quot;Visual Layout&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭──────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│ ❯ Ask anything...                                   │</span></span>
<span class="line"><span>╰──────────────────────────────────────────────────────╯</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li><strong>Border</strong>: full rounded box</li><li><strong>Prompt symbol</strong>: <code>❯</code> followed by space, then input text</li><li><strong>Cursor</strong>: solid block <code>█</code> when input is editable</li><li><strong>Background</strong>: theme background</li><li><strong>Suggestion list</strong>: renders below the input box, not inside it</li></ul><h3 id="multi-line-state" tabindex="-1">Multi-line state <a class="header-anchor" href="#multi-line-state" aria-label="Permalink to &quot;Multi-line state&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭──────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│ ❯ First line of input                               │</span></span>
<span class="line"><span>│   Second line (Shift+Enter was pressed)             │</span></span>
<span class="line"><span>│   Third line█                                       │</span></span>
<span class="line"><span>╰──────────────────────────────────────────────────────╯</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Lines beyond the first have <strong>2 spaces</strong> indent (aligns with text after <code>&gt; </code>).</p><hr><h2 id="border-color-states" tabindex="-1">Border Color States <a class="header-anchor" href="#border-color-states" aria-label="Permalink to &quot;Border Color States&quot;">​</a></h2><table tabindex="0"><thead><tr><th>State</th><th>Border color</th></tr></thead><tbody><tr><td>Default (idle / typing)</td><td><code>theme.prompt_border</code></td></tr><tr><td>Slash-command suggestions visible</td><td><code>theme.prompt_border</code></td></tr><tr><td>Agent thinking</td><td><code>theme.subtle</code></td></tr><tr><td>Provider/API-key overlay visible</td><td>input remains in place; dialog uses <code>theme.claude</code> border</td></tr></tbody></table><p>There is no separate shimmer border state in the current Rust implementation.</p><hr><h2 id="placeholder-text" tabindex="-1">Placeholder Text <a class="header-anchor" href="#placeholder-text" aria-label="Permalink to &quot;Placeholder Text&quot;">​</a></h2><p>Shown only when input is completely empty:</p><table tabindex="0"><thead><tr><th>Context</th><th>Placeholder</th></tr></thead><tbody><tr><td>Default</td><td><code>Ask anything...</code> (dimmed, <code>theme.inactive</code>)</td></tr></tbody></table><hr><h2 id="mode-prefixes" tabindex="-1">Mode Prefixes <a class="header-anchor" href="#mode-prefixes" aria-label="Permalink to &quot;Mode Prefixes&quot;">​</a></h2><p>Certain characters at the start of input trigger special modes:</p><table tabindex="0"><thead><tr><th>Prefix</th><th>Mode</th><th>Border color</th></tr></thead><tbody><tr><td><code>/</code></td><td>Slash command — dispatched to command system with typeahead menu</td><td><code>theme.prompt_border</code></td></tr></tbody></table><hr><h2 id="typeahead-autocomplete-dropdown" tabindex="-1">Typeahead / Autocomplete Dropdown <a class="header-anchor" href="#typeahead-autocomplete-dropdown" aria-label="Permalink to &quot;Typeahead / Autocomplete Dropdown&quot;">​</a></h2><p>Appears <strong>below</strong> the input bar when suggestions are available.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  › /connect              [cmd]   Connect a provider and save its API key</span></span>
<span class="line"><span>    /compact              [cmd]   Summarize conversation history to reduce...</span></span>
<span class="line"><span>    /cost                 [cmd]   Show the current session cost summary</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="dropdown-layout" tabindex="-1">Dropdown layout <a class="header-anchor" href="#dropdown-layout" aria-label="Permalink to &quot;Dropdown layout&quot;">​</a></h3><ul><li><strong>Position</strong>: Immediately below the input box, full width</li><li><strong>Max height</strong>: 5 rows</li><li><strong>Scroll</strong>: If more items than fit, scrolls (no scrollbar, just clips)</li></ul><h3 id="item-format" tabindex="-1">Item format <a class="header-anchor" href="#item-format" aria-label="Permalink to &quot;Item format&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  [indicator] /command-name   [cmd]   description</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><strong>Left indent</strong>: 2 spaces</li><li><strong>Focused item</strong>: orange text (<code>theme.claude</code>) with bold command label</li><li><strong>Unfocused</strong>: command name in <code>theme.text</code>, metadata/description in dim colors</li><li><strong>Tag</strong>: dimmed <code>[cmd]</code> badge</li><li><strong>Description</strong>: single-line truncated summary</li></ul><h3 id="suggestion-types-and-their-indicators" tabindex="-1">Suggestion types and their indicators <a class="header-anchor" href="#suggestion-types-and-their-indicators" aria-label="Permalink to &quot;Suggestion types and their indicators&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Indicator</th><th>Color</th></tr></thead><tbody><tr><td>Slash command</td><td><code>› </code> on focused row, otherwise two spaces</td><td><code>theme.claude</code> when focused, <code>theme.inactive</code> otherwise</td></tr></tbody></table><h3 id="keyboard-navigation" tabindex="-1">Keyboard navigation <a class="header-anchor" href="#keyboard-navigation" aria-label="Permalink to &quot;Keyboard navigation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>↓</code></td><td>Move focus down</td></tr><tr><td><code>↑</code></td><td>Move focus up</td></tr><tr><td><code>Tab</code></td><td>Accept focused suggestion</td></tr><tr><td><code>Esc</code></td><td>Dismiss dropdown</td></tr><tr><td><code>Enter</code></td><td>Accept focused suggestion AND submit</td></tr></tbody></table><hr><h2 id="image-paste-attachment-chips" tabindex="-1">Image Paste (Attachment Chips) <a class="header-anchor" href="#image-paste-attachment-chips" aria-label="Permalink to &quot;Image Paste (Attachment Chips)&quot;">​</a></h2><p>When user pastes an image from clipboard, a text chip is inserted at the cursor:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  &gt; Fix this error [Image #1] in the auth module</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="chip-appearance" tabindex="-1">Chip appearance <a class="header-anchor" href="#chip-appearance" aria-label="Permalink to &quot;Chip appearance&quot;">​</a></h3><ul><li><strong>Format</strong>: <code>[Image #N]</code> where N auto-increments from 1</li><li><strong>Normal state</strong>: standard input text color</li><li><strong>Cursor-on-chip state</strong>: inverted colors (chip selected for deletion)</li><li><strong>Deletion</strong>: Backspace at chip start deletes entire chip</li></ul><h3 id="text-paste-chips" tabindex="-1">Text paste chips <a class="header-anchor" href="#text-paste-chips" aria-label="Permalink to &quot;Text paste chips&quot;">​</a></h3><p>Large text pastes (&gt; ~5000 chars) become a reference chip:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  &gt; Here is the log output [Pasted text #1 +234 lines] what went wrong?</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>Format: <code>[Pasted text #N +M lines]</code> — M = number of newlines</li><li>Zero-line paste: <code>[Pasted text #N]</code></li><li>Truncated paste: <code>[...Truncated text #N +M lines...]</code></li></ul><hr><h2 id="input-history-navigation" tabindex="-1">Input History Navigation <a class="header-anchor" href="#input-history-navigation" aria-label="Permalink to &quot;Input History Navigation&quot;">​</a></h2><blockquote><p><strong>Status: ✅ Implemented in v0.5.0</strong> (<code>crates/piko-tui/src/history.rs</code>, <code>crates/piko-tui/src/app.rs</code>)</p></blockquote><p>When input is <strong>empty</strong>:</p><ul><li><code>↑</code> — replace input with previous submitted message</li><li><code>↓</code> — navigate forward in history (toward current empty)</li></ul><p>Visual: input text replaces, cursor goes to end.</p><p><strong>Implementation notes:</strong></p><ul><li><code>InputHistory</code> struct tracks <code>entries: Vec&lt;String&gt;</code> and <code>idx: Option&lt;usize&gt;</code>.</li><li>Whitespace-only submissions are silently ignored.</li><li><code>↑</code> when input has content but navigation is active continues navigating (allows full round-trips).</li><li>Typing while browsing exits navigation mode, keeping the recalled text editable.</li><li><code>↑</code>/<code>↓</code> fall back to chat-pane scroll when history is empty or not navigating.</li></ul><hr><h2 id="character-line-limits" tabindex="-1">Character/Line Limits <a class="header-anchor" href="#character-line-limits" aria-label="Permalink to &quot;Character/Line Limits&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Limit</th><th>Value</th><th>Behavior</th></tr></thead><tbody><tr><td>Max visible input lines</td><td>~10</td><td>Input scrolls vertically</td></tr><tr><td>Max paste inline</td><td>800 bytes or 2 lines</td><td>Larger becomes reference chip</td></tr><tr><td>Max input submit</td><td>No hard limit</td><td>Very large inputs may hit API limits</td></tr></tbody></table>`,55)])])}const m=t(i,[["render",o]]);export{u as __pageData,m as default};
